     }

     /**
-     * Usable columns/rows for full-size windows (excludes reserved shelf area).
+     * Usable area for full-size windows (excludes reserved shelf area).
+     * Returns {minCol, minRow, maxCol, maxRow} — the valid range for
+     * window top-left placement.
      */
-    get effectiveCols() {
-        if (!this._reserved) return this.cols;
-        // Right shelf: reserved starts at rv.col
-        // Left shelf: reserved ends at rv.col + rv.spanCols
-        const rv = this._reserved;
-        if (rv.col === 0) return this.cols - rv.spanCols; // left shelf
-        return rv.col; // right shelf (and top/bottom don't reduce cols)
-    }
+    getUsableArea(spanCols = 1, spanRows = 1) {
+        let minCol = 0, minRow = 0;
+        let maxCol = this.cols - spanCols;
+        let maxRow = this.rows - spanRows;
+
+        if (this._reserved) {
+            const rv = this._reserved;
+            // Right shelf
+            if (rv.col > 0 && rv.spanRows === this.rows)
+                maxCol = Math.min(maxCol, rv.col - spanCols);
+            // Left shelf
+            if (rv.col === 0 && rv.spanRows === this.rows)
+                minCol = rv.spanCols;
+            // Bottom shelf
+            if (rv.row > 0 && rv.spanCols === this.cols)
+                maxRow = Math.min(maxRow, rv.row - spanRows);
+            // Top shelf
+            if (rv.row === 0 && rv.spanCols === this.cols)
+                minRow = rv.spanRows;
+        }

-    get effectiveRows() {
-        if (!this._reserved) return this.rows;
-        const rv = this._reserved;
-        if (rv.row === 0 && rv.spanCols === this.cols) return this.rows - rv.spanRows; // top shelf
-        if (rv.row > 0 && rv.spanCols === this.cols) return rv.row; // bottom shelf
-        return this.rows;
+        return {
+            minCol: Math.max(0, minCol),
+            minRow: Math.max(0, minRow),
+            maxCol: Math.max(0, maxCol),
+            maxRow: Math.max(0, maxRow),
+        };
     }

